  function updateConnectionUI() {
    el.accountPill.textContent = `Account: ${state.account || "not connected"}`;
    el.chainPill.textContent = `Chain: ${state.chainId || "unknown"}`;
  }

  function updateContractUI() {
    const contractInfo = {
      address: state.contract?.target || null,
      functions: state.abi ? getAbiFunctionNames(state.abi) : [],
    };
    el.contractPreview.textContent = JSON.stringify(contractInfo, null, 2);
    const fnNames = contractInfo.functions;
    el.functionSelect.innerHTML = `<option value="">Select function</option>` + fnNames.map((f) => `<option value="${escapeHtml(f)}">${escapeHtml(f)}</option>`).join("");
  }

  async function connectWallet() {
    try {
      if (!window.ethereum) throw new Error("No injected wallet found");
      const browserProvider = new ethers.BrowserProvider(window.ethereum);
      await browserProvider.send("eth_requestAccounts", []);
      const signer = await browserProvider.getSigner();
      const network = await browserProvider.getNetwork();
      const account = await signer.getAddress();

      state.provider = browserProvider;
      state.signer = signer;
      state.account = account;
      state.chainId = network.chainId.toString();

      updateConnectionUI();
      setStatus("Wallet connected");
    } catch (err) {
      setStatus(err.message || String(err), true);
      setJson(el.resultPreview, { error: err.message || String(err) });
    }
  }

